example.code:
using var activity = _tracingHelper.StartActivity("ProcessOrder");
activity?.SetTag("order.id", orderId);
activity?.SetTag("customer.id", customerId);
try
{
    // Process order logic
    activity?.SetStatus(ActivityStatusCode.Ok);
}
catch (Exception ex)
{
    activity?.SetStatus(ActivityStatusCode.Error, ex.Message);
    activity?.RecordException(ex);
    throw;
}

private readonly Counter<long> _orderCounter;

public OrderService(MetricsHelper metricsHelper)
{
    _orderCounter = metricsHelper.CreateCounter<long>("orders.processed", "orders", "Total orders processed");
}

public void ProcessOrder(Order order)
{
    // Process order
    _orderCounter.Add(1, new KeyValuePair<string, object?>("status", "success"));
}

private readonly Histogram<double> _requestDuration;

public ApiController(MetricsHelper metricsHelper)
{
    _requestDuration = metricsHelper.CreateHistogram<double>("api.request.duration", "ms", "API request duration");
}

public async Task<IActionResult> GetData()
{
    var stopwatch = Stopwatch.StartNew();
    var result = await _service.GetDataAsync();
    _requestDuration.Record(stopwatch.ElapsedMilliseconds, new KeyValuePair<string, object?>("endpoint", "GetData"));
    return Ok(result);
}

private int _activeConnections = 0;

public ConnectionManager(MetricsHelper metricsHelper)
{
    metricsHelper.CreateObservableGauge("connections.active", () => _activeConnections, "connections", "Active connections");
}

private readonly UpDownCounter<int> _queueSize;

public QueueService(MetricsHelper metricsHelper)
{
    _queueSize = metricsHelper.CreateUpDownCounter<int>("queue.size", "items", "Queue size");
}

public void Enqueue(Item item)
{
    _queue.Enqueue(item);
    _queueSize.Add(1);
}

public Item Dequeue()
{
    var item = _queue.Dequeue();
    _queueSize.Add(-1);
    return item;
}
